firmware_template.source:
#include "haptic_drv2605.h"
#include <Wire.h>
#include <Adafruit_DRV2605.h>
static Adafruit_DRV2605 drv;
void haptic_setup(){Wire.begin();drv.begin();drv.selectLibrary(1);drv.setMode(DRV2605_MODE_INTTRIG);Serial.println("[haptic] OK");}
void haptic_play(uint8_t e){drv.setWaveform(0,e);drv.setWaveform(1,0);drv.go();}
void haptic_buzz(uint16_t ms){haptic_play(47);delay(ms);}
